   ```

### 思路

要使两边高度差小于等于1，并保证每层如此，直接将中间值作为根节点即可，每层都如此，这样能保证两边差只有1或者0

### 代码

```c++
class Solution {
public:
    TreeNode* sortedArrayToBST(vector<int> nums) {
        if(nums.size()==0)return NULL;
        TreeNode*newNode=new TreeNode();
        newNode->val=nums[(nums.size()-1)/2];
        newNode->left=sortedArrayToBST(vector<int>(nums.begin(),nums.begin()+(nums.size()-1)/2));
        newNode->right=sortedArrayToBST(vector<int>(nums.begin()+(nums.size()-1)/2+1,nums.end()));
        return newNode;
    }
};
```

